import boto3
from botocore.exceptions import NoCredentialsError

def publish_to_sqs(queue_url, user_data):
    try:
        # Initialize a session using your credentials
        session = boto3.Session(
            aws_access_key_id='YOUR_ACCESS_KEY',
            aws_secret_access_key='YOUR_SECRET_KEY',
            region_name='YOUR_REGION'
        )
        
        # Create an SQS client
        sqs = session.client('sqs')
        
        # Convert user data to a string format (e.g., JSON)
        message_body = str(user_data)
        
        # Publish the message to the queue
        response = sqs.send_message(
            QueueUrl=queue_url,
            MessageBody=message_body,
            DelaySeconds=10  # Optional: delay in seconds before delivery
        )
        
        print(f"Message sent successfully with ID: {response['MessageId']}")
    
    except NoCredentialsError:
        print("AWS credentials not available")
    except Exception as e:
        print(f"An error occurred: {e}")

